import pandas as pd
import numpy as np

# ODD Scoring Model: 15 metrics across 5 dimensions

dimensions = {
    'Revenue Quality': {
        'Recurring Revenue %': {'company': 75, 'benchmark': 85},
        'Contract Length (months avg)': {'company': 18, 'benchmark': 24},
        'Pricing Power (YoY increase %)': {'company': 3.2, 'benchmark': 5.0}
    },
    'Margin Quality': {
        'Gross Margin %': {'company': 58, 'benchmark': 65},
        'Variable Cost %': {'company': 35, 'benchmark': 42},
        'Supplier Concentration (Top 3 %)': {'company': 45, 'benchmark': 30}
    },
    'Customer Health': {
        'Customer Churn %': {'company': 12, 'benchmark': 8},
        'NPS Score': {'company': 38, 'benchmark': 52},
        'Top 10 Customer Concentration %': {'company': 28, 'benchmark': 18}
    },
    'Competitive Position': {
        'Market Share %': {'company': 8.5, 'benchmark': 12},
        'Market Share Trend (3-yr CAGR %)': {'company': 2.1, 'benchmark': 4.5},
        'Switching Cost (relative scale 1-10)': {'company': 4, 'benchmark': 7}
    },
    'Operational Maturity': {
        'Process Automation %': {'company': 35, 'benchmark': 55},
        'Headcount to Revenue efficiency': {'company': 3.2, 'benchmark': 2.5},
        'Capacity Utilization %': {'company': 72, 'benchmark': 85}
    }
}

# Score each metric on 1-5 scale based on distance from benchmark
metric_scores = {}
for dimension, metrics in dimensions.items():
    metric_scores[dimension] = {}
    for metric, values in metrics.items():
        gap_pct = ((values['company'] - values['benchmark']) / values['benchmark']) * 100
        if gap_pct >= 0:
            score = 5  # Company at or above benchmark
        elif gap_pct >= -10:
            score = 4  # Within 10% of benchmark
        elif gap_pct >= -20:
            score = 3  # Within 20% of benchmark
        elif gap_pct >= -35:
            score = 2  # Within 35% of benchmark
        else:
            score = 1  # More than 35% below benchmark
        metric_scores[dimension][metric] = score

# Create scoring DataFrame
scoring_data = []
for dimension, metrics in metric_scores.items():
    for metric, score in metrics.items():
        company_val = dimensions[dimension][metric]['company']
        benchmark_val = dimensions[dimension][metric]['benchmark']
        gap_pct = ((company_val - benchmark_val) / benchmark_val) * 100
        scoring_data.append({
            'Dimension': dimension,
            'Metric': metric,
            'Company': company_val,
            'Benchmark': benchmark_val,
            'Gap %': f'{gap_pct:.1f}%',
            'Score (1-5)': score
        })

scoring_df = pd.DataFrame(scoring_data)

# Dimension-level weights
dimension_weights = {
    'Revenue Quality': 0.20,
    'Margin Quality': 0.22,
    'Customer Health': 0.18,
    'Competitive Position': 0.18,
    'Operational Maturity': 0.22
}

# Calculate dimension averages
dimension_scores = {}
for dimension in dimensions.keys():
    dim_scores = scoring_df[scoring_df['Dimension'] == dimension]['Score (1-5)'].values
    dimension_scores[dimension] = np.mean(dim_scores)

# Calculate weighted overall score
overall_score = sum(dimension_scores[d] * dimension_weights[d] for d in dimensions.keys())

print('OPERATIONAL DUE DILIGENCE SCORECARD')
print('='*80)
print('\nDetailed Metric Scores:\n')
print(scoring_df.to_string(index=False))
print('\n\nDimension Summary Scores:')
for dimension in dimensions.keys():
    score = dimension_scores[dimension]
    weight = dimension_weights[dimension]
    weighted = score * weight
    print(f'{dimension:.<30} {score:.2f}/5.0 (weight: {weight:.0%}, weighted: {weighted:.3f})')

print(f'\nOVERALL ODD SCORE: {overall_score:.2f}/5.0')

if overall_score >= 4.0:
    print('Assessment: STRONG — Business quality supports current valuation multiple')
elif overall_score >= 3.0:
    print('Assessment: MODERATE — Significant operational value creation opportunity exists')
else:
    print('Assessment: WEAK — Substantial operational improvements required; valuation discount warranted')

print('\n\nValue Creation Opportunity Analysis:')
print('-'*80)
sorted_dimensions = sorted(dimension_scores.items(), key=lambda x: x[1])
for i, (dimension, score) in enumerate(sorted_dimensions, 1):
    print(f'{i}. {dimension} ({score:.2f}/5.0) — PRIORITY IMPROVEMENT AREA')

