            'Dimension': dimension,
            'Metric': metric,
            'Company': values['company'],
            'Benchmark': values['benchmark'],
            'Gap %': f'{gap_pct:.1f}%',
            'Score': score
        })
    dimension_scores_fsd[dimension] = np.mean(dim_scores)

